<template>
  <van-tabbar v-model="active">
    <van-tabbar-item name="home" route="true" to="/home" icon="home-o">主页</van-tabbar-item>
    <van-tabbar-item name="search" route="true" to="/search" icon="search">搜索</van-tabbar-item>
  </van-tabbar>
</template>

<script>
  import Vue from 'vue';
  import { Tabbar, TabbarItem } from 'vant';

  Vue.use(Tabbar).use(TabbarItem);
    export default {
        name: "tabbar",
        data(){
          return{
            active:'home'
          }
        },
        component:{
          Tabbar, TabbarItem
        },

      //vue提供的生命周期钩子回调函数，修复刷新后routeview与tabbar不一致的问题
      created(){
        this.active = this.$route.path.substr(1);//调用sub方法把斜杠去掉
      }
    }
</script>

<style scoped lang="stylus" ref="stylesheet/stylus">

</style>



