//1.引入router模块
import Vue from 'vue';
import VueRouter from 'vue-router';
import Home from './../vue/Home/Home';
import Search from './../vue/Search/Search';
//2.用vue声明使用
Vue.use(VueRouter);

//3.输出路由对象
export default new VueRouter({
  routes:[
    {
      path:'/',
      redirect:'/home'
    },
    {
      path:'/home',
      component:Home
    },
    {
      path:'/search',
      component:Search
    },
  ]

});

